import React from "react";
import Navbar from "../components/Navbar";
import "../styles.css";

function Home() {
  return (
    <div>
      <Navbar />

      <div className="hero">
        <h1>Изучайте новые навыки онлайн</h1>
        <p>Найдите курсы по программированию и технологиям</p>

        <input placeholder="Поиск курсов..." />
      </div>
    </div>
  );
}

export default Home;
